import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    priority: 'normal',
    metadata: { orderId: 'order-1' },
    createdAt: new Date('2026-01-15T10:00:00Z'),
    status: 'sent',
    sentAt: new Date('2026-01-15T10:00:01Z'),
    error: null,
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let eventBus: EventBus;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository, eventBus);
    resetNotificationLogIdCounter();
  });

  describe('event-driven logging', () => {
    it('should log a sent notification via notification:sent event', async () => {
      const notification = makeNotification();

      await eventBus.emit({
        type: 'notification:sent',
        notification,
        timestamp: new Date('2026-01-15T10:00:01Z'),
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.error).toBeNull();
    });

    it('should log a failed notification via notification:failed event', async () => {
      const notification = makeNotification({
        id: 'notif-0002',
        status: 'failed',
        error: 'Connection timeout',
      });

      await eventBus.emit({
        type: 'notification:failed',
        notification,
        error: 'Connection timeout',
        timestamp: new Date('2026-01-15T10:00:01Z'),
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toBe('Connection timeout');
    });

    it('should log multiple notifications with sequential IDs', async () => {
      const n1 = makeNotification({ id: 'notif-0001' });
      const n2 = makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' });

      await eventBus.emit({ type: 'notification:sent', notification: n1, timestamp: new Date() });
      await eventBus.emit({ type: 'notification:sent', notification: n2, timestamp: new Date() });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(2);
      expect(logs[0]?.id).toBe('nlog-0001');
      expect(logs[1]?.id).toBe('nlog-0002');
    });
  });

  describe('integration with NotificationService', () => {
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      resetNotificationIdCounter();
    });

    it('should automatically log notifications sent through the notification service', async () => {
      await notificationService.createAndSend({
        type: 'order_confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.status).toBe('sent');
    });

    it('should log notifications triggered by domain events', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.status).toBe('sent');
    });

    it('should log failed notifications from adapter errors', async () => {
      const failingAdapter = new EmailAdapter({
        fromAddress: 'test@example.com',
        transport: async () => { throw new Error('Transport failed'); },
      });
      const failService = new NotificationService(eventBus);
      failService.registerAdapter(failingAdapter);

      await failService.createAndSend({
        type: 'order_confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
      });

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toBe('Transport failed');
    });
  });

  describe('query by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      const n1 = makeNotification({ id: 'notif-0001', recipient: 'alice@example.com' });
      const n2 = makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' });
      const n3 = makeNotification({ id: 'notif-0003', recipient: 'alice@example.com' });

      await eventBus.emit({ type: 'notification:sent', notification: n1, timestamp: new Date() });
      await eventBus.emit({ type: 'notification:sent', notification: n2, timestamp: new Date() });
      await eventBus.emit({ type: 'notification:sent', notification: n3, timestamp: new Date() });

      const aliceLogs = historyService.getByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(2);
      expect(aliceLogs.every((l) => l.recipient === 'alice@example.com')).toBe(true);

      const bobLogs = historyService.getByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
    });

    it('should return empty array for unknown recipient', () => {
      expect(historyService.getByRecipient('nobody@example.com')).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    it('should return logs for a specific notification type', async () => {
      const n1 = makeNotification({ id: 'notif-0001', type: 'order_confirmation' });
      const n2 = makeNotification({ id: 'notif-0002', type: 'order_status_update' });

      await eventBus.emit({ type: 'notification:sent', notification: n1, timestamp: new Date() });
      await eventBus.emit({ type: 'notification:sent', notification: n2, timestamp: new Date() });

      const confirmLogs = historyService.getByType('order_confirmation');
      expect(confirmLogs).toHaveLength(1);
      expect(confirmLogs[0]?.type).toBe('order_confirmation');
    });
  });

  describe('query by date range', () => {
    it('should return logs within the specified date range', async () => {
      const jan = new Date('2026-01-15T10:00:00Z');
      const feb = new Date('2026-02-15T10:00:00Z');
      const mar = new Date('2026-03-15T10:00:00Z');

      const n1 = makeNotification({ id: 'notif-0001' });
      const n2 = makeNotification({ id: 'notif-0002' });
      const n3 = makeNotification({ id: 'notif-0003' });

      await eventBus.emit({ type: 'notification:sent', notification: n1, timestamp: jan });
      await eventBus.emit({ type: 'notification:sent', notification: n2, timestamp: feb });
      await eventBus.emit({ type: 'notification:sent', notification: n3, timestamp: mar });

      const janToFeb = historyService.getByDateRange(
        new Date('2026-01-01T00:00:00Z'),
        new Date('2026-02-28T23:59:59Z'),
      );
      expect(janToFeb).toHaveLength(2);

      const marOnly = historyService.getByDateRange(
        new Date('2026-03-01T00:00:00Z'),
        new Date('2026-03-31T23:59:59Z'),
      );
      expect(marOnly).toHaveLength(1);
    });

    it('should return empty array for date range with no logs', () => {
      const result = historyService.getByDateRange(
        new Date('2025-01-01T00:00:00Z'),
        new Date('2025-12-31T23:59:59Z'),
      );
      expect(result).toHaveLength(0);
    });
  });

  describe('combined query', () => {
    it('should filter by multiple criteria', async () => {
      const n1 = makeNotification({ id: 'notif-0001', recipient: 'alice@example.com', type: 'order_confirmation' });
      const n2 = makeNotification({ id: 'notif-0002', recipient: 'alice@example.com', type: 'order_status_update' });
      const n3 = makeNotification({ id: 'notif-0003', recipient: 'bob@example.com', type: 'order_confirmation' });

      await eventBus.emit({ type: 'notification:sent', notification: n1, timestamp: new Date('2026-01-15T10:00:00Z') });
      await eventBus.emit({ type: 'notification:sent', notification: n2, timestamp: new Date('2026-01-15T10:00:00Z') });
      await eventBus.emit({ type: 'notification:sent', notification: n3, timestamp: new Date('2026-01-15T10:00:00Z') });

      const result = historyService.query({
        recipient: 'alice@example.com',
        type: 'order_confirmation',
      });
      expect(result).toHaveLength(1);
      expect(result[0]?.notificationId).toBe('notif-0001');
    });

    it('should filter by status', async () => {
      const n1 = makeNotification({ id: 'notif-0001' });
      const n2 = makeNotification({ id: 'notif-0002', status: 'failed', error: 'fail' });

      await eventBus.emit({ type: 'notification:sent', notification: n1, timestamp: new Date() });
      await eventBus.emit({ type: 'notification:failed', notification: n2, error: 'fail', timestamp: new Date() });

      const sent = historyService.query({ status: 'sent' });
      expect(sent).toHaveLength(1);

      const failed = historyService.query({ status: 'failed' });
      expect(failed).toHaveLength(1);
    });

    it('should return all logs when no filters are provided', async () => {
      const n1 = makeNotification({ id: 'notif-0001' });
      const n2 = makeNotification({ id: 'notif-0002' });

      await eventBus.emit({ type: 'notification:sent', notification: n1, timestamp: new Date() });
      await eventBus.emit({ type: 'notification:sent', notification: n2, timestamp: new Date() });

      expect(historyService.query({})).toHaveLength(2);
    });
  });

  describe('getCount', () => {
    it('should return the total count of log entries', async () => {
      expect(historyService.getCount()).toBe(0);

      const n1 = makeNotification({ id: 'notif-0001' });
      await eventBus.emit({ type: 'notification:sent', notification: n1, timestamp: new Date() });

      expect(historyService.getCount()).toBe(1);
    });
  });
});

